Trong React 18 concurrent rendering, output của component tree này là gì?

function App() {
  return (
    <React.Suspense fallback={<Spinner />}>
      <Dashboard />
    </React.Suspense>
  );
}

function Dashboard() {
  const user = useSuspenseQuery({ queryKey: ['user'], queryFn: fetchUser });
  return <div>{user.name}</div>;
}
